mapper.select:
SELECT * FROM ( SELECT ROWNUM rn, a.* FROM ( SELECT m.MEMBERID AS memberId, c.COMPANY_NAME AS companyName, c.BIZ_NO AS bizNo, c.INDUSTRY_CODE AS industryCode, m.STATUS AS status, CASE c.APPROVED_YN WHEN 0 THEN 'PENDING' WHEN 1 THEN 'APPROVED' WHEN 2 THEN 'REJECTED' END AS approvedYn, c.REJECT_REASON AS rejectReason, COUNT(jp.job_id) AS postCount, m.CREATED_AT AS createdAt FROM TBL_MEMBER m JOIN TBL_COMPANY c ON m.MEMBERID = c.FK_MEMBERID LEFT JOIN TBL_JOB_POSTING jp ON m.MEMBERID = jp.FK_MEMBERID
m.TYPE = 1
AND ( c.COMPANY_NAME LIKE '%' || #{search} || '%' OR c.BIZ_NO LIKE '%' || #{search} || '%' )
AND m.STATUS = #{status}
AND c.APPROVED_YN = CASE #{approval} WHEN 'APPROVED' THEN 1 WHEN 'REJECTED' THEN 2 WHEN 'PENDING' THEN 0 END
GROUP BY m.MEMBERID, c.COMPANY_NAME, c.BIZ_NO, c.INDUSTRY_CODE, m.STATUS, c.APPROVED_YN, c.REJECT_REASON, m.CREATED_AT ORDER BY m.CREATED_AT DESC ) a WHERE ROWNUM <= #{offset} + #{limit} ) WHERE rn > #{offset}
